module RefModule(
   input bit_one,
   input bit_two,
   input carry_in,
   output result,
   output carry_out
   );wire   unused_in_or;
  wire   carry_or;
  wire   in_and;

  assign unused_in_or = bit_one ^ bit_two;
  assign carry_or = unused_in_or & carry_in;
  assign in_and = bit_one & bit_two;
  assign result   = unused_in_or ^ carry_in;
  assign carry_out = carry_or | in_and;endmodule
